module top_module(A, B, sel, C);parameter WIDTH = 8;
   input [WIDTH-1:0] A, B;
   input sel;
   output [WIDTH-1:0] C;

   reg [WIDTH-1:0]    X_C_reg;

   always @(*)
   begin
      if (sel == 0)
         X_C_reg = A + B;
      else
         X_C_reg = A - B;
   end

   assign C = X_C_reg;
endmodule
